retriever = vectorstore.as_retriever(
    search_type="mmr",
    search_kwargs={
        "k": 6,            # final result count
        "fetch_k": 20,     # candidate pool for MMR selection
        "lambda_mult": 0.5,  # 0=max diversity, 1=max relevance
    },
)

# Only retrieve from a specific document type
retriever = vectorstore.as_retriever(
    search_kwargs={
        "k": 6,
        "filter": {"doc_type": "earnings_release", "year": 2025},
    },
)
